import psycopg2
from getpass import getpass

def install_extension(conn, extension_name):
    try:
        cur = conn.cursor()
        cur.execute(f"CREATE EXTENSION IF NOT EXISTS {extension_name}")
        conn.commit()
        print(f"Extension '{extension_name}' installed successfully.")
    except Exception as e:
        print(f"Error installing extension: {e}")

def main():
    host = input("Enter database host: ")
    db_name = input("Enter database name: ")
    user = input("Enter database username: ")
    password = getpass("Enter database password: ")

    conn = psycopg2.connect(
        host=host,
        database=db_name,
        user=user,
        password=password
    )

    while True:
        extension_name = input("Enter extension name (or 'exit' to quit): ")
        if extension_name.lower() == "exit":
            break
        install_extension(conn, extension_name)

if __name__ == "__main__":
    main()